import React, { useState, useEffect } from 'react';
import { getProblems, createProblem, getAllSubmissions } from './services/api';

function App() {
  const [problems, setProblems] = useState([]);
  const [submissions, setSubmissions] = useState([]);
  const [newProblem, setNewProblem] = useState({ title: '', description: '', difficulty: 'Easy', sampleInput: '', sampleOutput: '' });

  useEffect(() => {
    fetchData();
  }, []);

  const fetchData = async () => {
    try {
      const probRes = await getProblems();
      setProblems(probRes.data);
      const subRes = await getAllSubmissions();
      setSubmissions(subRes.data);
    } catch (err) {
      console.error("Failed to fetch data. Make sure you are logged in as Admin.");
    }
  };

  const handleCreateProblem = async (e) => {
    e.preventDefault();
    try {
      await createProblem(newProblem);
      alert('Problem Created Successfully!');
      fetchData();
      setNewProblem({ title: '', description: '', difficulty: 'Easy', sampleInput: '', sampleOutput: '' });
    } catch (err) {
      alert('Error creating problem. Are you admin?');
    }
  };

  return (
    <div style={{ fontFamily: 'Arial', padding: '20px' }}>
      <h1>CodeTrack Admin Portal</h1>
      <div style={{ display: 'flex', gap: '20px' }}>

        {/* Create Problem */}
        <div style={{ flex: 1, border: '1px solid #ccc', padding: '15px' }}>
          <h2>Add New Problem</h2>
          <form onSubmit={handleCreateProblem} style={{ display: 'flex', flexDirection: 'column', gap: '10px' }}>
            <input type="text" placeholder="Title" value={newProblem.title} onChange={e => setNewProblem({...newProblem, title: e.target.value})} required />
            <textarea placeholder="Description" value={newProblem.description} onChange={e => setNewProblem({...newProblem, description: e.target.value})} required />
            <select value={newProblem.difficulty} onChange={e => setNewProblem({...newProblem, difficulty: e.target.value})}>
              <option value="Easy">Easy</option>
              <option value="Medium">Medium</option>
              <option value="Hard">Hard</option>
            </select>
            <textarea placeholder="Sample Input" value={newProblem.sampleInput} onChange={e => setNewProblem({...newProblem, sampleInput: e.target.value})} required />
            <textarea placeholder="Sample Output" value={newProblem.sampleOutput} onChange={e => setNewProblem({...newProblem, sampleOutput: e.target.value})} required />
            <button type="submit" style={{ background: '#28a745', color: 'white', border: 'none', padding: '10px' }}>Create Problem</button>
          </form>
        </div>

        {/* View Problems & Submissions */}
        <div style={{ flex: 2, display: 'flex', flexDirection: 'column', gap: '20px' }}>
          <div style={{ border: '1px solid #ccc', padding: '15px' }}>
            <h2>All Problems</h2>
            <ul>
              {problems.map(p => (
                <li key={p._id}><strong>{p.title}</strong> - {p.difficulty} (ID: {p._id})</li>
              ))}
            </ul>
          </div>

          <div style={{ border: '1px solid #ccc', padding: '15px' }}>
            <h2>All Student Submissions</h2>
            <table style={{ width: '100%', textAlign: 'left', borderCollapse: 'collapse' }}>
              <thead>
                <tr style={{ background: '#eee' }}>
                  <th style={{ padding: '8px' }}>Student</th>
                  <th style={{ padding: '8px' }}>Problem</th>
                  <th style={{ padding: '8px' }}>Status</th>
                </tr>
              </thead>
              <tbody>
                {submissions.map(s => (
                  <tr key={s._id} style={{ borderBottom: '1px solid #eee' }}>
                    <td style={{ padding: '8px' }}>{s.userId?.name} ({s.userId?.registerNumber})</td>
                    <td style={{ padding: '8px' }}>{s.problemId?.title}</td>
                    <td style={{ padding: '8px' }}>{s.status}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>

      </div>
    </div>
  );
}

export default App;
